    /* BALANCE CARDS */
    .balance-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 16px; margin-bottom: 32px; }
    .balance-card { padding: 24px; background: var(--bg-surface-1); border: 1px solid var(--border-default); border-radius: 14px; }
    .balance-card-label { font-size: 12px; color: var(--text-tertiary); text-transform: uppercase; letter-spacing: 0.08em; font-weight: 600; margin-bottom: 8px; }
    .balance-card-value { font-family: var(--font-display); font-size: 32px; font-weight: 700; }
    .balance-card-value--available { color: var(--positive); }
    .balance-card-value--pending { color: var(--warning); }
    .balance-card-sub { font-size: 12px; color: var(--text-tertiary); margin-top: 4px; font-family: var(--font-mono); }

    /* TABLE */
    .table-container { background: var(--bg-surface-1); border: 1px solid var(--border-default); border-radius: 14px; overflow: hidden; margin-bottom: 32px; }
    .table-header-row { display: flex; padding: 12px 24px; border-bottom: 1px solid var(--border-default); background: var(--bg-surface-2); }
    .table-header-row span { font-family: var(--font-heading); font-size: 12px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.08em; color: var(--text-tertiary); }
    .table-row { display: flex; padding: 16px 24px; border-bottom: 1px solid var(--border-default); align-items: center; }
    .table-row:last-child { border-bottom: none; }
    .col-date { flex: 1; }
    .col-amount { flex: 0.8; }
    .col-status { flex: 0.8; }
    .col-method { flex: 1; }
    .table-cell { font-size: 14px; color: var(--text-secondary); }
    .table-cell--strong { color: var(--text-primary); font-weight: 500; }

    .badge { font-family: var(--font-heading); font-size: 11px; font-weight: 600; padding: 3px 10px; border-radius: 999px; display: inline-block; }
    .badge--completed { color: var(--positive); background: rgba(16,185,129,0.12); border: 1px solid rgba(16,185,129,0.3); }
    .badge--pending { color: var(--warning); background: rgba(245,158,11,0.12); border: 1px solid rgba(245,158,11,0.3); }
    .badge--processing { color: var(--brand-primary); background: rgba(139,92,246,0.12); border: 1px solid rgba(139,92,246,0.3); }

    .btn { font-family: var(--font-heading); font-weight: 600; font-size: 14px; padding: 12px 28px; border-radius: 12px; border: none; cursor: pointer; transition: all 0.15s; display: inline-flex; align-items: center; gap: 8px; text-decoration: none; }
    .btn-primary { background: var(--brand-primary); color: white; box-shadow: 0 0 20px rgba(139,92,246,0.2); }
    .btn-outline { background: transparent; color: var(--text-secondary); border: 1px solid var(--border-default); }

    .section-label { font-family: var(--font-heading); font-size: 11px; font-weight: 600; letter-spacing: 0.12em; text-transform: uppercase; color: var(--text-tertiary); margin-bottom: 16px; display: flex; align-items: center; gap: 12px; }

    /* SETTINGS SECTION */
    .settings-card { padding: 24px; background: var(--bg-surface-1); border: 1px solid var(--border-default); border-radius: 14px; margin-bottom: 24px; }
    .settings-card-title { font-family: var(--font-heading); font-weight: 700; font-size: 16px; margin-bottom: 16px; }
    .stripe-placeholder { display: flex; align-items: center; gap: 16px; padding: 20px; background: var(--bg-surface-2); border: 1px solid var(--border-default); border-radius: 12px; margin-bottom: 16px; }
    .stripe-icon { width: 48px; height: 32px; background: linear-gradient(135deg, #635BFF, #7A73FF); border-radius: 6px; display: flex; align-items: center; justify-content: center; font-family: var(--font-heading); font-weight: 700; font-size: 12px; color: white; letter-spacing: 0.05em; }
    .stripe-info { flex: 1; }
    .stripe-info-title { font-weight: 600; font-size: 14px; margin-bottom: 2px; }
    .stripe-info-desc { font-size: 12px; color: var(--text-tertiary); }
    .stripe-status { font-size: 12px; color: var(--positive); font-weight: 600; }

    .setting-row { display: flex; justify-content: space-between; align-items: center; padding: 16px 0; border-bottom: 1px solid var(--border-default); }
    .setting-row:last-child { border-bottom: none; }
    .setting-label { font-size: 14px; color: var(--text-secondary); }
    .setting-value { font-size: 14px; font-weight: 500; font-family: var(--font-mono); }

    /* STATE SEPARATOR */
    .state-separator { display: flex; align-items: center; gap: 16px; margin: 48px 0; padding: 0 48px; }
    .state-separator-line { flex: 1; height: 1px; border-top: 2px dashed var(--border-strong); }
    .state-separator-label { font-family: var(--font-mono); font-size: 12px; color: var(--brand-secondary); background: rgba(255,120,73,0.08); border: 1px dashed rgba(255,120,73,0.3); padding: 6px 16px; border-radius: 999px; white-space: nowrap; }

    /* FOOTER */
    .footer { padding: 48px 48px 32px; border-top: 1px solid var(--border-default); }
    .footer-inner { max-width: 1344px; margin: 0 auto; display: flex; align-items: center; justify-content: space-between; }
    .footer-logo { font-family: var(--font-display); font-weight: 700; font-size: 18px; background: linear-gradient(135deg, var(--brand-primary), #A78BFA); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
    .footer-links { display: flex; gap: 24px; }
    .footer-links a { font-size: 13px; color: var(--text-tertiary); text-decoration: none; }
    .footer-social { display: flex; gap: 12px; }
    .footer-social-icon { width: 32px; height: 32px; border-radius: 8px; background: var(--bg-surface-2); border: 1px solid var(--border-default); display: flex; align-items: center; justify-content: center; color: var(--text-tertiary); }
    .footer-social-icon svg { width: 14px; height: 14px; }
    .footer-copyright { text-align: center; margin-top: 28px; font-size: 12px; color: var(--text-tertiary); max-width: 1344px; margin-left: auto; margin-right: auto; }

    /* MOBILE */
    .mobile-frame .page-content { padding: 24px 20px; }
    .mobile-frame .page-title { font-size: 28px; }
    .mobile-frame .balance-grid { grid-template-columns: 1fr; gap: 10px; }
    .mobile-frame .balance-card-value { font-size: 26px; }
    .mobile-frame .table-container { overflow-x: auto; }
    .mobile-frame .table-header-row, .mobile-frame .table-row { min-width: 500px; }
    .mobile-frame .footer { padding: 32px 20px 24px; }
    .mobile-frame .footer-inner { flex-direction: column; gap: 20px; text-align: center; }
    .mobile-frame .footer-links { flex-wrap: wrap; justify-content: center; gap: 16px; }
    .mobile-frame .footer-copyright { margin-top: 16px; }
    .mobile-frame .annotation { display: none; }
  </style>
